export function handleAccessTokenErrorResponse(event: H3Event, oauthProvider: OAuthProvider, oauthError: any, onError?: OnError) {
  const message = `${upperFirst(oauthProvider)} login failed: ${oauthError.error_description || oauthError.error || 'Unknown error'}`

  const error = createError({
    statusCode: 401,
    message,
    data: oauthError,
  })

  if (!onError) throw error
  return onError(event, error)
}

export function handleMissingConfiguration(event: H3Event, provider: OAuthProvider, missingKeys: string[], onError?: OnError) {
  const environmentVariables = missingKeys.map(key => `NUXT_OAUTH_${provider.toUpperCase()}_${snakeCase(key).toUpperCase()}`)

  const error = createError({
    statusCode: 500,
    message: `Missing ${environmentVariables.join(' or ')} env ${missingKeys.length > 1 ? 'variables' : 'variable'}.`,
  })

  if (!onError) throw error
  return onError(event, error)
}

export async function verifyJwt<T>(
  token: string,
  options: JWTVerifyOptions,
): Promise<T> {
  const JWKS = jose.createRemoteJWKSet(new URL(options.publicJwkUrl))

  const { payload } = await jose.jwtVerify(token, JWKS, {
    audience: options.audience,
    issuer: options.issuer,
  })

  return payload as T
}

export function useNitroApp(): NitroApp {
  let instance: NitroApp | undefined = (useNitroApp as any)._instance;
  if (instance) {
    return instance;
  }
  instance = (useNitroApp as any)._instance = createNitroApp();
  globalThis.__nitro__ = globalThis.__nitro__ || {};
  globalThis.__nitro__[APP_ID] = instance;
  initNitroPlugins(instance);
  return instance;
}

export default eventHandler(async (event) => {
  const { sql } = await readBody(event)
  const collection = getRouterParam(event, 'collection')! || event.path?.split('/')?.[2] || ''

  assertSafeQuery(sql, collection)

  const conf = useRuntimeConfig().content as RuntimeConfig['content']
  if (conf.integrityCheck) {
    await checkAndImportDatabaseIntegrity(event, collection, conf)
  }

  return loadDatabaseAdapter(conf).all(sql)
})

export function usePortal(portal: Ref<boolean | string | HTMLElement | undefined>) {
  const globalPortal = inject(portalTargetInjectionKey, undefined)

  const value = computed(() => portal.value === true ? globalPortal?.value : portal.value)

  const disabled = computed(() => typeof value.value === 'boolean' ? !value.value : false)
  const to = computed(() => typeof value.value === 'boolean' ? 'body' : value.value)

  return computed(() => ({
    to: to.value,
    disabled: disabled.value
  }))
}

async function onClickWrapper(event: MouseEvent) {
  loadingAutoState.value = true
  const callbacks = Array.isArray(props.onClick) ? props.onClick : [props.onClick]
  try {
    await Promise.all(callbacks.map(fn => fn?.(event)))
  } finally {
    loadingAutoState.value = false
  }
}

const getHostLocale = (
  event: H3Event | undefined,
  path: string,
  domainLocales: I18nPublicRuntimeConfig['domainLocales'],
) => {
  const host = import.meta.client
    ? new URL(window.location.href).host
    : getRequestURL(event!, { xForwardedHost: true }).host

  const locales = normalizedLocales.map(l => ({
    ...l,
    domain: domainLocales[l.code]?.domain ?? l.domain,
  }))
  return matchDomainLocale(locales, host, getLocaleFromRoutePath(path))
}

export async function initializeI18nContext(event: H3Event) {
  const runtimeI18n = useRuntimeI18n(undefined, event)
  const defaultLocale: string = runtimeI18n.defaultLocale || ''
  const options = await setupVueI18nOptions(getDefaultLocaleForDomain(getHost(event)) || defaultLocale)
  const localeConfigs = createLocaleConfigs(options.fallbackLocale)
  const ctx = createI18nContext()

  ctx.vueI18nOptions = options
  ctx.localeConfigs = localeConfigs

  event.context.nuxtI18n = ctx
  return ctx
}

