export function isPathInScope(pathname: string, base: string): boolean {
  let canonical: string;
  try {
    const pre = pathname.replace(/%2f/gi, "/").replace(/%5c/gi, "\\");
    canonical = new URL(pre, "http://_").pathname;
  } catch {
    return false;
  }
  return !base || canonical === base || canonical.startsWith(base + "/");
}

export async function getLocalGitInfo(rootDir: string): Promise<GitInfo | undefined> {
  const remote = await getLocalGitRemote(rootDir)
  if (!remote) {
    return
  }

  // https://www.npmjs.com/package/git-url-parse#clipboard-example
  const { name, owner, source } = gitUrlParse(remote)
  const url = `https://${source}/${owner}/${name}`

  return {
    name,
    owner,
    url,
  }
}

export function parseDensities(input: string | undefined = ''): number[] {
  if (input === undefined || !input.length) {
    return []
  }

  const densities = new Set<number>()
  for (const density of input.split(' ')) {
    const d = Number.parseInt(density.replace('x', ''))
    if (d) {
      densities.add(d)
    }
  }

  return Array.from(densities)
}

function deduplicateArray<T = unknown> (maybeArray: T): T {
  if (!Array.isArray(maybeArray)) { return maybeArray }

  const fresh: any[] = []
  const hashes = new Set<string>()
  for (const item of maybeArray) {
    const _hash = hash(item)
    if (!hashes.has(_hash)) {
      hashes.add(_hash)
      fresh.push(item)
    }
  }
  return fresh as T
}

export function getBaseSchema<
  ChildType extends z.ZodAny | z.AnyZodObject = z.ZodAny,
>(schema: ChildType | z.ZodEffects<ChildType>): ChildType | null {
  if (!schema)
    return null
  if ('innerType' in schema._def)
    return getBaseSchema(schema._def.innerType as ChildType)

  if ('schema' in schema._def)
    return getBaseSchema(schema._def.schema as ChildType)

  return schema as ChildType
}

export function serverFetch(
  resource: string | URL | Request,
  init?: RequestInit,
  context?: ServerRequestContext | H3EventContext
): Promise<Response> {
  const req = toRequest(resource, init);
  req.context = { ...req.context, ...context };
  const appHandler = useNitroApp().fetch;
  try {
    return Promise.resolve(appHandler(req));
  } catch (error) {
    return Promise.reject(error);
  }
}

export function fetch(
  resource: string | URL | Request,
  init?: RequestInit,
  context?: ServerRequestContext | H3EventContext
): Promise<Response> {
  if (typeof resource === "string" && resource.charCodeAt(0) === 47) {
    return serverFetch(resource, init, context);
  }
  resource = (resource as any)._request || resource; // unwrap srvx request
  return globalThis.fetch(resource, init);
}

function awsEventHeaders(event: APIGatewayProxyEvent | APIGatewayProxyEventV2): Headers {
  const headers = new Headers();
  for (const [key, value] of Object.entries(event.headers)) {
    if (value) {
      headers.set(key, value);
    }
  }
  if ("cookies" in event && event.cookies) {
    for (const cookie of event.cookies) {
      headers.append("cookie", cookie);
    }
  }
  return headers;
}

export function resolveCollections(collections: Record<string, DefinedCollection>): ResolvedCollection[] {
  collections.info = {
    type: 'data',
    source: undefined,
    schema: infoStandardSchema,
    extendedSchema: infoStandardSchema,
    fields: {},
  }

  return Object.entries(collections)
    .map(([name, collection]) => resolveCollection(name, collection))
    .filter(Boolean) as ResolvedCollection[]
}

function getOptionsFilepath(options: LocalOptionSearchOptions) {
  let hashedKey

  if (options.key)
    hashedKey = hash(`${options.root}:${options.key}`)
  else
    hashedKey = hash(options.root)

  const home = getHomeDir()
  const filePath = join(home, '.nuxt/devtools', `${hashedKey}.json`)

  return {
    filePath,
    hashedKey,
  }
}

export function telemetryEvent(payload: object, immediate = false) {
  if (!telemetry)
    return

  if (getOptions()?.behavior.telemetry === false)
    return

  telemetry.createEvent('devtools', payload)

  if (immediate)
    telemetry.sendEvents()
  else
    throttledSend()
}

function syncClient() {
  if (!client.inspector)
    client.inspector = getInspectorInstance()

  try {
    iframe?.contentWindow?.__NUXT_DEVTOOLS_VIEW__?.setClient(client)
  }
  catch (e) {
    // cross-origin
    console.error('[nuxt-devtools] Failed to connect view', e)
  }
  return client
}

export function parseSize(input: string | number | undefined = '') {
  if (typeof input === 'number') {
    return input
  }
  if (typeof input === 'string') {
    if (input.replace('px', '').match(/^\d+$/g)) {
      return Number.parseInt(input, 10)
    }
  }
}

export async function resolveProviders(nuxt: any, options: ModuleOptions): Promise<ImageModuleProvider[]> {
  const providers: ImageModuleProvider[] = []

  for (const key in options) {
    if (BuiltInProviders.includes(key as ImageProviderName)) {
      providers.push(await resolveProvider(nuxt, key, { provider: key, options: options[key as keyof ConfiguredImageProviders] }))
    }
  }

  for (const key in options.providers) {
    providers.push(await resolveProvider(nuxt, key, options.providers[key]))
  }

  return providers
}

export default defineProvider<ImagekitOptions>({
  getImage: (src, { modifiers, baseURL = '/' }) => {
    let operations = operationsGenerator(modifiers)

    operations = operations.replace('c-pad_resize', 'cm-pad_resize')
    operations = operations.replace('c-pad_extract', 'cm-pad_extract')
    operations = operations.replace('c-extract', 'cm-extract')
    operations = operations.replace('raw-', '')

    return {
      url: joinURL(baseURL, (operations ? withQuery(src, { tr: operations }) : src)),
    }
  },
})

export async function resolvePath (path: string, opts: ResolvePathOptions = {}): Promise<string> {
  const { type = 'file' } = opts

  const res = await _resolvePathGranularly(path, { ...opts, type })

  if (res.type === type) {
    return res.path
  }

  // Return normalized input
  return opts.fallbackToOriginal ? path : res.path
}

const collapse = (value?: boolean) => {
  if (!opts.value.collapsible) {
    return
  }

  const newCollapsed = value ?? !isCollapsed.value
  if (newCollapsed && !isCollapsed.value) {
    previousSize.value = size.value
  } else if (!newCollapsed && isCollapsed.value) {
    size.value = previousSize.value
  }

  isCollapsed.value = newCollapsed
}

function mapLinks(links: ContentSearchLink[]): ContentSearchItem[] {
  return links.flatMap(link => [{
    ...link,
    suffix: link.description,
    description: undefined,
    icon: link.icon || appConfig.ui.icons.file,
    children: undefined
  } as ContentSearchItem, ...(link.children?.map(child => ({
    ...child,
    prefix: link.label ? link.label + ' >' : undefined,
    suffix: child.description,
    description: undefined,
    icon: child.icon || link.icon || appConfig.ui.icons.file
  } as ContentSearchItem)) || [])])
}

export function findBrowserLocale(locales: Locale[], browserLocales: readonly string[]): string {
  const matchedLocales = matchBrowserLocale(
    locales.map(l => ({ code: l.code, language: l.language || l.code })),
    browserLocales,
  )

  return matchedLocales.sort(compareBrowserLocale).at(0)?.code ?? ''
}

export function defaultColors(count: number = 3) {
  const quotient = Math.floor(count / 2)
  const remainder = count % 2

  const primaryCount = quotient + remainder
  const secondaryCount = quotient
  return [
    ...Array.from({ length: primaryCount }, () => `var(--vis-primary-color)`),
    ...Array.from({ length: secondaryCount }, () => `var(--vis-secondary-color)`),
  ]
}

