export function retentionToCron(retention: string): string {
  const { totalMinutes } = parseRetention(retention)

  const halfMinutes = Math.max(1, Math.floor(totalMinutes / 2))

  if (halfMinutes < 60) {
    return `*/${halfMinutes} * * * *`
  }

  const halfHours = Math.floor(halfMinutes / 60)
  if (halfHours >= 24) {
    return '0 3 * * *'
  }

  return `0 */${halfHours} * * *`
}

